@State — a property wrapper that gives a SwiftUI view local mutable storage. Marking a struct property with @State tells SwiftUI to allocate persistent storage outside the value-type view; mutating the wrapped value triggers re-evaluation of `body`.

@Binding — a two-way reference to a value owned elsewhere. A child view receives a Binding and reads/writes the parent's @State without owning it.

Rules:
• @State must be `private` and used for view-local state (not shared models).
• Use $ to project a Binding from @State (`$count`).
• Bindings drive controls like Toggle, TextField, Picker.

code_example:
struct Counter: View {
  @State private var value = 0
  var body: some View {
    VStack {
      Text("\(value)").font(.largeTitle)
      Stepper(value: $value, in: 0...100) { Text("Count") }
      ResetButton(value: $value) // pass binding down
    }
  }
}

struct ResetButton: View {
  @Binding var value: Int
  var body: some View {
    Button("Reset") { value = 0 }
  }
}

// Binding from a non-@State source — Binding<Value> is a value, you can construct it
struct LoggedToggle: View {
  let isOn: Bool
  let onChange: (Bool) -> Void
  var body: some View {
    Toggle("On", isOn: Binding(get: { isOn }, set: onChange))
  }
}

// Bindings work with arrays via $array[index]
struct ListEditor: View {
  @State private var items = ["a", "b", "c"]
  var body: some View {
    ForEach($items.indices, id: \.self) { i in
      TextField("item", text: $items[i])
    }
  }
}

final class CartViewModel: ObservableObject {
  @Published var items: [String] = []
  func add(_ item: String) { items.append(item) }
}

// ✅ Owner — creates and keeps the model alive
struct CartView: View {
  @StateObject private var vm = CartViewModel()
  var body: some View {
    VStack {
      Text("\(vm.items.count) items")
      Button("Add") { vm.add("x") }
      CartFooter(vm: vm) // pass down
    }
  }
}

// ✅ Downstream — observes a model owned elsewhere
struct CartFooter: View {
  @ObservedObject var vm: CartViewModel
  var body: some View { Text("Total: \(vm.items.count)") }
}

// ❌ Wrong — using @ObservedObject for a fresh instance
struct Buggy: View {
  @ObservedObject var vm = CartViewModel() // recreated on every re-render!
  var body: some View { Text("\(vm.items.count)") }
}

// ✅ iOS 17+ — Observation framework, simpler still
@Observable
final class FeedVM {
  var items: [String] = []
}
struct FeedView: View {
  @State private var vm = FeedVM() // @Observable models work with plain @State
  var body: some View { Text("\(vm.items.count)") }
}

answer:
@EnvironmentObject reads an ObservableObject from the SwiftUI environment — a global-ish dependency-injection mechanism scoped to a view subtree. You inject the object once at the top of the tree with `.environmentObject(...)` and any descendant can read it without prop-drilling.

Use for cross-cutting state that many views need: the current user, theme, feature flags, navigation router.

Forget to inject? The app crashes when the descendant first reads it. Pair with EnvironmentValues + custom keys for value-type / non-ObservableObject values.

code_example:
final class AppSession: ObservableObject {
  @Published var currentUser: User?
  func login(_ user: User) { currentUser = user }
  func logout() { currentUser = nil }
}

// Inject at the root
@main
struct MyApp: App {
  @StateObject private var session = AppSession()
  var body: some Scene {
    WindowGroup {
      RootView()
        .environmentObject(session)
    }
  }
}

// Anywhere in the subtree
struct ProfileButton: View {
  @EnvironmentObject private var session: AppSession
  var body: some View {
    if let user = session.currentUser {
      Text(user.name)
    } else {
      Button("Sign in") { session.login(.demo) }
    }
  }
}

// EnvironmentValues — for non-ObservableObject values (theme, formatter, etc.)
private struct ThemeKey: EnvironmentKey {
  static let defaultValue: Theme = .system
}
extension EnvironmentValues {
  var theme: Theme {
    get { self[ThemeKey.self] } set { self[ThemeKey.self] = newValue }
  }
}

struct ThemedView: View {
  @Environment(\.theme) private var theme
  var body: some View { /* ... */ EmptyView() }
}

// Inject
RootView().environment(\.theme, .dark)

import SwiftUI
import Observation

@Observable
final class FeedVM {
  var posts: [Post] = []
  var query: String = ""
  var loading: Bool = false
  func reload() async { /* ... */ }
}

// Owner uses plain @State
struct FeedView: View {
  @State private var vm = FeedVM()
  var body: some View {
    VStack {
      // Reading vm.query here causes re-render only when query changes
      TextField("Search", text: $vm.query)
        .onSubmit { Task { await vm.reload() } }
      List(vm.posts) { Text($0.title) }
    }
  }
}

// Pass model down — no @ObservedObject
struct FeedFooter: View {
  let vm: FeedVM
  var body: some View {
    // Only re-renders if posts.count changes — even if other vm props mutate
    Text("\(vm.posts.count) items")
  }
}

// @Bindable for editing nested objects
struct EditView: View {
  @Bindable var post: Post // Post is @Observable
  var body: some View {
    TextField("Title", text: $post.title)
  }
}

// Structural identity reset
struct Demo: View {
  @State var showHeader = false
  var body: some View {
    VStack {
      if showHeader { HeaderView() }
      DetailView()              // identity changes when HeaderView appears/disappears
      // because its position in the VStack shifts
    }
  }
}

// Explicit identity — driving full reset
struct Quiz: View {
  @State var question = 0
  var body: some View {
    QuestionView(index: question)
      .id(question) // each new question gets a fresh QuestionView lifetime
  }
}

// Identity for ForEach — pass Identifiable models or stable id
ForEach(items, id: \.id) { item in Row(item: item) }
// Avoid id: \.self for mutable models — duplicates and drift cause flicker

// Fine-grained dependency tracking with @Observable
@Observable final class VM { var x = 0; var y = 0 }
struct ReadX: View {
  let vm: VM
  var body: some View { Text("\(vm.x)") } // re-renders only on vm.x change
}

// Equatable opt-in — skip body when prop hasn't changed
struct ExpensiveRow: View, Equatable {
  let item: Item
  static func == (l: Self, r: Self) -> Bool { l.item.id == r.item.id }
  var body: some View { /* ... */ EmptyView() }
}
ExpensiveRow(item: x).equatable()

@Observable final class FeedVM {
  var posts: [Post] = []
  var error: Error?
  var isLoading = false
  func reload() async {
    isLoading = true
    defer { isLoading = false }
    do { posts = try await api.posts() } catch { self.error = error }
  }
}

struct FeedView: View {
  @State private var vm = FeedVM()
  let userId: String

  var body: some View {
    List(vm.posts) { Text($0.title) }
      .overlay { if vm.isLoading { ProgressView() } }
      .task(id: userId) {            // re-runs when userId changes
        await vm.reload()
      }
      .refreshable { await vm.reload() }
      .alert("Error", isPresented: .constant(vm.error != nil)) {
        Button("OK") { vm.error = nil }
      } message: { Text(vm.error?.localizedDescription ?? "") }
  }
}

// .task with cancellation — when the view disappears, the underlying Task is cancelled
// (URLSession, sleep, TaskGroup, etc. all honor cancellation).

// Custom async work outside the view — use Task.detached only when you need it to
// outlive the view (rare in SwiftUI).
